/**
 * Replaces the last '-'-separated segment of context.currentNode.id with the supplied nodeId.
 *
 * @param {string|number} nodeId - The short id to splice into the current node path.
 * @returns {string} The fully-qualified node id, or the original nodeId if no path is set.
 */
__makeLocalNodeId = function (nodeId) {
    if (nodeId !== null && nodeId !== undefined) nodeId = nodeId.toString();
    if (!context.currentNode.id)
        return nodeId;
    var separator = '-';
    var output = context.currentNode.id.split(separator);
    output[output.length - 1] = nodeId;
    return output.join(separator);
};

/**
 * Evaluates a string as a JS template literal using variables from scope.
 * Use only with trusted, platform-controlled inputs.
 *
 * @param {string} tpl - Template literal body (no backticks).
 * @param {object} scope - Map of variable names to values made available in the template.
 * @returns {string} The evaluated template string.
 */
__resolveTemplate = function (tpl, scope) {
    var keys = Object.keys(scope);
    var vals = [];
    for (var i = 0; i < keys.length; i++) {
        vals.push(scope[keys[i]]);
    }
    return new Function(keys.join(','), 'return `' + tpl + '`').apply(null, vals);
};

/**
 * Normalises operation config. Accepts a JSON string, an RTDS operation object with a Params field, or a flat Params object.
 *
 * @param {string|object} config - The raw operation config to normalise.
 * @returns {object} The flat Params object, never null.
 */
__extractParams = function (config) {
    var parsed = typeof config === 'string' ? JSON.parse(config) : config;
    if (parsed && typeof parsed.Params === 'object' && parsed.Params !== null) {
        return parsed.Params;
    }
    return parsed || {};
};

var callScope = {};
/**
 * Pure version of __init: returns a map of resolved __rt* values without mutating globals.
 * Active is coerced to Boolean; ConfigId and Timeout are coerced to Number with fallbacks.
 *
 * @param {string|object} config - Raw operation config (see __extractParams).
 * @returns {object} Map of '__rt' + Key to resolved value.
 */
__setupConfig = function (config) {
    var params = __extractParams(config);
    var result = {};
    result.__rtActive = typeof params.Active === 'boolean' ? params.Active : Boolean(params.Active);
    var keys = Object.keys(params);
    for (var i = 0; i < keys.length; i++) {
        var key = keys[i];
        if (key === 'Active') { continue; }
        var raw = (params[key] !== undefined && params[key] !== null) ? String(params[key]).trim() : '';
        var resolved;
        if (raw.indexOf('${') !== -1) {
            try { resolved = __resolveTemplate(raw, callScope); }
            catch (e) { log_debug('[__setupConfig] Template resolve failed for key "' + key + '", falling back to raw. Error: ' + e.message); resolved = raw; }
        } else { resolved = raw; }
        if (key === 'ConfigId') { resolved = Number(resolved) || __rtConfigId; }
        else if (key === 'Timeout') { resolved = resolved !== '' ? Number(resolved) : __rtTimeout; }
        result['__rt' + key] = resolved;
    }
    return result;
};

/**
 * Walks the Params object and writes resolved values into the corresponding global __rt<Key> or __rt<TypePrefix><Key> variable.
 * Only whole-string ${var} templates are resolved; partial templates are left raw with a debug log.
 *
 * @param {string|object} config - Raw operation config (see __extractParams).
 * @returns {void} Mutates global in place; returns nothing.
 */
__init = function (config) {
    var params = __extractParams(config);
    for (var key in params) {
        if (!params.hasOwnProperty(key)) { continue; }
        var candidates = ['__rt' + key, '__rt{{ComponentName}}' + key];
        var targetVar = null;
        for (var i = 0; i < candidates.length; i++) {
            if (global.hasOwnProperty(candidates[i])) { targetVar = candidates[i]; break; }
        }
        if (targetVar === null) { continue; }
        var raw = (params[key] !== null && params[key] !== undefined) ? String(params[key]) : '';
        if (raw.indexOf('${') !== -1) {
            var match = raw.match(/^\$\{([^}]+)\}$/);
            if (match && global.hasOwnProperty(match[1])) { global[targetVar] = String(global[match[1]]); }
            else { log_debug('[__init] Could not resolve template "' + raw + '" for key "' + key + '" - leaving default: ' + global[targetVar]); }
            continue;
        }
        global[targetVar] = raw.trim();
    }
};

